sql:
SELECT b.beach_name, b.location, c.county_name
FROM beaches b
JOIN counties c ON b.county_id = c.county_id;

external_knowledge:
- "shimmering stars" refers to beaches with consistently good water quality;
- "golden threshold" is a metaphor for a high quality standard, indicated as an average test result above 3.0;
- "past two years" means the period from the last two years reported in the annual reports.

sql:
SELECT COUNT(beach_id) AS beach_count
FROM beaches
WHERE county_id = 1;

SELECT AVG(average_test_result) AS average_test_result
FROM annual_reports
WHERE year = 2022;

SELECT beach_name, beach_id
FROM beaches
ORDER BY last_inspection_date DESC;

SELECT beach_name 
FROM beaches 
WHERE last_inspection_date = (SELECT MAX(last_inspection_date) FROM beaches);

SELECT beach_name
FROM beaches
ORDER BY beach_name;
